#include <stdio.h>
#include <string.h>

void backtrack(char *buf, int pos, int open, int close, int n) {
    if (pos == 2 * n) {
        buf[pos] = '\0';
        printf("%s\n", buf);
        return;
    }
    if (open < n) {
        buf[pos] = '(';
        backtrack(buf, pos + 1, open + 1, close, n);
    }
    if (close < open) {
        buf[pos] = ')';
        backtrack(buf, pos + 1, open, close + 1, n);
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        scanf("%d", &n);
        char buf[20]; // 2*8 + 1 = 17, 20 is safe
        backtrack(buf, 0, 0, 0, n);
    }
    return 0;
}

