code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static void dfs(StringBuilder sb, int open, int close, int n, BufferedWriter out) throws IOException {
        if (sb.length() == 2 * n) {
            out.write(sb.toString());
            out.newLine();
            return;
        }
        if (open < n) {
            sb.append('(');
            dfs(sb, open + 1, close, n, out);
            sb.deleteCharAt(sb.length() - 1);
        }
        if (close < open) {
            sb.append(')');
            dfs(sb, open, close + 1, n, out);
            sb.deleteCharAt(sb.length() - 1);
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        BufferedWriter out = new BufferedWriter(new OutputStreamWriter(System.out));
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            int n = Integer.parseInt(br.readLine().trim());
            dfs(new StringBuilder(), 0, 0, n, out);
        }
        out.flush();
    }
}

