import sys

def backtrack(buf, open_cnt, close_cnt, n, out):
    if len(buf) == 2 * n:
        out.append(''.join(buf))
        return
    if open_cnt < n:
        buf.append('(')
        backtrack(buf, open_cnt + 1, close_cnt, n, out)
        buf.pop()
    if close_cnt < open_cnt:
        buf.append(')')
        backtrack(buf, open_cnt, close_cnt + 1, n, out)
        buf.pop()

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(T):
        n = int(data[idx]); idx += 1
        backtrack([], 0, 0, n, out_lines)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

